  AND target_type = #{targetType}
  AND target_id = #{targetId}

SELECT
    -- 是否点赞：1=已点赞 0=未点赞
    EXISTS (
        SELECT 1 FROM `likes`
        WHERE user_id = #{userId}
          AND target_type= 1
          AND target_id = #{postId}
    ) AS is_liked,
    -- 是否收藏：1=已收藏 0=未收藏
    EXISTS (
        SELECT 1
        FROM collection_posts cp
                 JOIN collections c ON cp.collection_id = c.id
        WHERE c.user_id = #{userId}
          AND cp.post_id = #{postId}
    ) AS is_collected;

